import SwiftUI
struct LoginView:View{@EnvironmentObject var app:AppState;@State private var url=UserDefaults.standard.string(forKey:"serverURL") ?? "http://localhost:3000";@State private var identifier="";@State private var password="";var body:some View{NavigationStack{ScrollView{VStack(spacing:22){Image(systemName:"server.rack").font(.system(size:54)).foregroundStyle(.cyan);VStack(spacing:5){Text("Nas Hub").font(.largeTitle.bold());Text("Your server, at a glance").foregroundStyle(.secondary)};VStack(spacing:14){TextField("Server URL",text:$url).textInputAutocapitalization(.never).keyboardType(.URL).textContentType(.URL);TextField("Username or email",text:$identifier).textInputAutocapitalization(.never).textContentType(.username);SecureField("Password",text:$password).textContentType(.password)}.textFieldStyle(.roundedBorder);if let error=app.error{Text(error).foregroundStyle(.red).font(.callout)};Button{Task{await app.login(url:url,identifier:identifier,password:password)}}label:{Group{if app.loading{ProgressView()}else{Text("Sign In").bold()}}.frame(maxWidth:.infinity).padding(.vertical,6)}.buttonStyle(.borderedProminent).disabled(app.loading||identifier.isEmpty||password.isEmpty);Text("Development may use HTTP. Production deployments must use HTTPS and WSS.").font(.caption).foregroundStyle(.secondary)}}.padding(28).frame(maxWidth:520)}.navigationTitle("Sign in")}}

